1	import { describe, it, expect } from "vitest";
2	import { runScenario } from "./claim-office.js";
3	
4	describe("MHPCO Claim Office", () => {
5	  // Simplest case
6	  it("empty item list → premium 5 G (only processing fee)", () => {
7	    const result = runScenario({
8	      customer: { yearsWithMHPCO: 0 },
9	      steps: [{ op: "quote", items: [] }],
10	    });
11	    expect(result).toEqual({ results: [{ premium: 5 }] });
12	  });
13	
14	  // Base premiums per item type
15	  it("single sword (newcomer) → premium 115 G (100 base + 10 first insurance + 5 fee)", () => {
16	    const result = runScenario({
17	      customer: { yearsWithMHPCO: 0 },
18	      steps: [{ op: "quote", items: [{ type: "sword" }] }],
19	    });
20	    expect(result).toEqual({ results: [{ premium: 115 }] });
21	  });
22	  it("single amulet (newcomer) → premium 71 G (60 base + 6 first insurance + 5 fee)", () => {
23	    const result = runScenario({
24	      customer: { yearsWithMHPCO: 0 },
25	      steps: [{ op: "quote", items: [{ type: "amulet" }] }],
26	    });
27	    expect(result).toEqual({ results: [{ premium: 71 }] });
28	  });
29	  it("single staff (newcomer) → premium 93 G (80 base + 8 first insurance + 5 fee)", () => {
30	    const result = runScenario({
31	      customer: { yearsWithMHPCO: 0 },
32	      steps: [{ op: "quote", items: [{ type: "staff" }] }],
33	    });
34	    expect(result).toEqual({ results: [{ premium: 93 }] });
35	  });
36	  it("single potion (newcomer) → premium 49 G (40 base + 4 first insurance + 5 fee)", () => {
37	    const result = runScenario({
38	      customer: { yearsWithMHPCO: 0 },
39	      steps: [{ op: "quote", items: [{ type: "potion" }] }],
40	    });
41	    expect(result).toEqual({ results: [{ premium: 49 }] });
42	  });
43	
44	  // Components
45	  it("single rune (newcomer) → premium 33 G (25 base + 2.5 first insurance + 5 fee rounded up)", () => {
46	    const result = runScenario({
47	      customer: { yearsWithMHPCO: 0 },
48	      steps: [{ op: "quote", items: [{ type: "rune" }] }],
49	    });
50	    expect(result).toEqual({ results: [{ premium: 33 }] });
51	  });
52	  it("2 runes (newcomer) → premium 60 G (50 base + 5 first insurance + 5 fee)", () => {
53	    const result = runScenario({
54	      customer: { yearsWithMHPCO: 0 },
55	      steps: [{ op: "quote", items: [{ type: "rune" }, { type: "rune" }] }],
56	    });
57	    expect(result).toEqual({ results: [{ premium: 60 }] });
58	  });
59	
60	  // Block discount for 3 alike components
61	  it("3 runes (newcomer) → premium 71 G (60 base via block + 6 first insurance + 5 fee)", () => {
62	    const result = runScenario({
63	      customer: { yearsWithMHPCO: 0 },
64	      steps: [{ op: "quote", items: [{ type: "rune" }, { type: "rune" }, { type: "rune" }] }],
65	    });
66	    expect(result).toEqual({ results: [{ premium: 71 }] });
67	  });
68	  it("4 runes (newcomer) → premium 115 G (100 base no block + 10 first ins + 5 fee)", () => {
69	    const result = runScenario({
70	      customer: { yearsWithMHPCO: 0 },
71	      steps: [{ op: "quote", items: [{ type: "rune" }, { type: "rune" }, { type: "rune" }, { type: "rune" }] }],
72	    });
73	    expect(result).toEqual({ results: [{ premium: 115 }] });
74	  });
75	  it.todo("7 runes → premium 180 G (175 base + 5 fee)");
76	
77	  // Alike means same type
78	  it.todo("2 runes + 1 moonstone → premium 80 G (75 base, no block + 5 fee)");
79	  it.todo("3 runes + 3 moonstones → premium 125 G (120 base, two blocks + 5 fee)");
80	
81	  // First insurance surcharge (per item, +10%)
82	  it.todo("newcomer single sword (no previous contract) → first insurance applies to item; premium 115 G (100 + 10 + 5)");
83	
84	  // Cursed surcharge (+50% of item's base premium)
85	  it.todo("newcomer cursed sword (steel, enchantment 3) → premium 165 G (100 base + 50 curse + 10 first insurance + 5 fee)");
86	
87	  // High enchantment surcharge (≥5 → +30%)
88	  it.todo("sword with enchantment 5 → high-enchantment surcharge applies (130 + 10 first + 5 = 145 G for newcomer)");
89	  it.todo("sword with enchantment 4 → no high-enchantment surcharge (100 + 10 first + 5 = 115 G for newcomer)");
90	  it.todo("cursed sword with enchantment 5 → both curse and high-enchantment surcharges apply");
91	
92	  // Loyalty discount (≥2 years → -20% on policy base premium)
93	  it.todo("loyal customer (exactly 2 years) single sword → loyalty discount applies");
94	
95	  // Follow-up contract discount (-15% on policy base premium)
96	  it.todo("second quote for same customer → follow-up contract discount applies");
97	
98	  // Modifier scope on multi-item policies
99	  it.todo("policy with cursed sword + plain amulet → cursed surcharge only on sword (210 G before fee)");
100	
101	  // Rounding in MHPCO's favor (premium rounded up)
102	  it.todo("premium calculation yielding 197.5 G → final premium 198 G (rounded up)");
103	
104	  // Integration examples
105	  it.todo("newcomer with cursed sword → premium 165 G");
106	  it.todo("long-standing customer's second contract with cursed sword enchantment 7 → premium 160 G");
107	
108	  // ---- Claim processing ----
109	
110	  // Standard reimbursement
111	  it.todo("regular sword (steel, enchantment 3), damage 500 G → payout 400 G (500 - 100 deductible)");
112	  it.todo("rune damaged (insurance value 250 G), damage 200 G → payout 100 G (no special clause)");
113	
114	  // High enchantment clause (≥8 → 50% reimbursement)
115	  it.todo("steel sword, enchantment 9, damage 1000 G → payout 400 G (50% then deductible)");
116	
117	  // Dragon material clause (full reimbursement)
118	  it.todo("dragon-material sword, enchantment 5, damage 800 G → payout 700 G (full minus deductible)");
119	
120	  // Both clauses → 50% rule wins
121	  it.todo("dragon-material sword, enchantment 9, damage 1000 G → payout 400 G");
122	  it.todo("dragon-material sword, enchantment exactly 8, damage 1000 G → payout 400 G");
123	
124	  // Deductible per damage event
125	  it.todo("dragon attack damages sword (500 G) and amulet (300 G) → payout 600 G (deductible per item)");
126	
127	  // Multiple items of same type
128	  it.todo("policy covers two swords → insurance sum 2000 G, cap 4000 G");
129	  it.todo("dragon attack damages both swords (two damage entries) → each treated separately with own deductible");
130	  it.todo("damages array has more entries of a type than policy covers → CLI exits non-zero");
131	
132	  // Cap exhaustion
133	  it.todo("policy covers sword + amulet → insurance sum 1600 G, cap 3200 G");
134	  it.todo("cursed sword → cap 2000 G (based on unmodified insurance value, not modified premium)");
135	  it.todo("policy covers sword + 3 runes (block) → insurance sum 1750 G (block discount affects premium only)");
136	  it.todo("sword cap 2000 G, two claims of 1500 G each → first payout 1400 G, second 600 G");
137	
138	  // Rounding payout (down, in MHPCO's favor)
139	  it.todo("payout calculation yielding 350.5 G → final payout 350 G (rounded down)");
140	
141	  // Edge cases — errors
142	  it.todo("quote with unknown item type → CLI exits non-zero, error to stderr, no results");
143	  it.todo("claim references damage with item not in policy → CLI exits non-zero");
144	  it.todo("claim damage with negative amount → CLI exits non-zero");
145	});
146

1	type Item = { type: string };
2	type Step = { op: "quote"; items: Item[] };
3	type Scenario = { customer: { yearsWithMHPCO: number }; steps: Step[] };
4	
5	const PROCESSING_FEE = 5;
6	const FIRST_INSURANCE_SURCHARGE_RATE = 0.1;
7	const COMPONENT_TYPES = new Set(["rune", "moonstone"]);
8	const COMPONENT_BASE = 25;
9	const BLOCK_SIZE = 3;
10	const BLOCK_BASE = 60;
11	
12	const BASE_PREMIUMS: Record<string, number> = {
13	  sword: 100,
14	  amulet: 60,
15	  staff: 80,
16	  potion: 40,
17	  rune: COMPONENT_BASE,
18	  moonstone: COMPONENT_BASE,
19	};
20	
21	const componentBlockPrice = (count: number): number => {
22	  if (count === BLOCK_SIZE) return BLOCK_BASE;
23	  return count * COMPONENT_BASE;
24	};
25	
26	const baseTotalForItems = (items: Item[]): number => {
27	  const componentCounts = new Map<string, number>();
28	  let total = 0;
29	  for (const item of items) {
30	    if (COMPONENT_TYPES.has(item.type)) {
31	      componentCounts.set(item.type, (componentCounts.get(item.type) ?? 0) + 1);
32	    } else {
33	      total += BASE_PREMIUMS[item.type];
34	    }
35	  }
36	  for (const count of componentCounts.values()) {
37	    total += componentBlockPrice(count);
38	  }
39	  return total;
40	};
41	
42	const quoteItems = (items: Item[]): number => {
43	  const base = baseTotalForItems(items);
44	  const firstInsuranceSurcharge = base * FIRST_INSURANCE_SURCHARGE_RATE;
45	  return Math.ceil(base + firstInsuranceSurcharge + PROCESSING_FEE);
46	};
47	
48	export const runScenario = (input: Scenario): { results: { premium: number }[] } => {
49	  const results = input.steps.map((step) => ({ premium: quoteItems(step.items) }));
50	  return { results };
51	};
